const allItems = $input.first().json.documents;
const size = 1000;
const outputItems = [];

for (const item of allItems) {
  const text = item.text || '';
  const fileName = item.fileName || 'unknown.pdf';

  for (let i = 0; i < text.length; i += size) {
    outputItems.push({
      json: {
        content: text.slice(i, i + size),
        metadata: {
          source: fileName,
          chunk_id: Math.floor(i / size)
        }
      }
    });
  }
}

return outputItems;

