const items = $input.all();
const firstItem = items[0]; // JSON object
const binaryItems = items.slice(1); // Remaining are binary files

return binaryItems.map((item) => ({
  binary: {
    data: item.binary.data 
  },
  json: {
    id: firstItem.json.data.id 
  }
}));

return {
  type: "info",
  content: {
    answer: $('send_message').first().json.data.answer.replace(/\[ID:\d+\]/g, ''),
    sources: $('send_message').first().json.data.reference.doc_aggs ? $('send_message').first().json.data.reference.doc_aggs.map((doc) => ({
      filename: doc.doc_name,
      pageNumber: 1
    })) : []
  }
};

const rawInput = $input.first()?.json?.output;
let targetTables;

try {
  targetTables = JSON.parse(rawInput);
} catch {
  return [];
}

if (!Array.isArray(targetTables) || targetTables.length === 0) return [];

const targetSet = new Set(targetTables.map(t => t.trim().toLowerCase()));
const data = $('Aggregate').first()?.json?.data;

if (!Array.isArray(data)) return [];

const filtered = data.filter(t =>
  targetSet.has(t.table_name?.trim().toLowerCase())
);

return { tables: filtered };

const typeMap = {
  "integer": "i",
  "bigint": "b",
  "character varying": "s",
  "numeric": "n",
  "USER-DEFINED": "u",
  "jsonb": "j"
};

const compressed = {
  t: [], 
  types: typeMap
};

for (const table of $input.first().json.data) {
  const tableName = table.table_name;
  const columns = table.columns.map((col) => {
    const typeCode = typeMap.hasOwnProperty(col.data_type)
      ? typeMap[col.data_type]
      : col.data_type;
    return [col.column_name, typeCode];
  });
  compressed.t.push([tableName, columns]);
}

return compressed;
